/**
 * TownScene — Scene that wraps the town experience.
 *
 * Entered via SceneManager.transition('town', { town }) or when
 * EventBus emits 'scene:town'. Delegates all UI to TownPanel.
 *
 * @module TownScene
 */

import DebugLog from '../debug/DebugLog.js';
import EventBus from '../core/EventBus.js';
import TownPanel from '../ui/TownPanel.js';
import WorldState from '../world/WorldState.js';

export default class TownScene {
  constructor() {
    /** @type {object|null} */
    this._renderer = null;

    /** @type {Function|null} EventBus unsubscribe handles */
    this._unsubExit = null;
  }

  /**
   * Initialize the scene. Called by SceneManager with { renderer, ...data }.
   * @param {{ renderer: object, town?: object }} options
   */
  async init({ renderer, town } = {}) {
    this._renderer = renderer;

    // Listen for the exit event so we can transition back to the world
    this._unsubExit = EventBus.on('town:exit', () => {
      this._onExit();
    });

    const townData = town ?? WorldState.currentTown ?? null;
    TownPanel.show(townData);

    DebugLog.info(`[world] TownScene init; town=${townData?.name ?? '(none)'}`);
  }

  /** Called every frame by SceneManager — nothing to tick in town. */
  update(_deltaTime) {}

  /**
   * Tear down the scene. Called by SceneManager before transitioning away.
   */
  async destroy() {
    if (this._unsubExit) {
      this._unsubExit();
      this._unsubExit = null;
    }

    TownPanel.hide();

    DebugLog.info('[world] TownScene destroyed');
  }

  // ─── Private ─────────────────────────────────────────────────────────────

  /**
   * Handle the player choosing to leave town.
   * Transitions back to localMap (or worldMap as fallback).
   */
  _onExit() {
    // Determine which scene to return to
    const returnScene = WorldState.currentLocalMapId !== null ? 'localMap' : 'worldMap';

    DebugLog.info(`[world] TownScene: leave town → ${returnScene}`);

    // Lazy-import SceneManager to avoid circular deps at module level
    import('../core/SceneManager.js').then(({ default: SceneManager }) => {
      SceneManager.transition(returnScene);
    }).catch(err => {
      DebugLog.error(`[world] TownScene exit transition failed: ${err.message}`);
    });
  }
}
